1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const INSURANCE_VALUE_MULTIPLIER = 10;
24	const insuranceValueFor = (type: string): number => BASE_PREMIUMS[type] * INSURANCE_VALUE_MULTIPLIER;
25	const DEDUCTIBLE = 100;
26	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
27	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
28	const CAP_MULTIPLIER = 2;
29	
30	type Item = { type: string; cursed?: boolean; enchantment?: number };
31	type QuoteStep = { op: "quote"; items: Array<Item> };
32	type Damage = { itemType: string; amount: number };
33	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<Damage> } };
34	type Step = QuoteStep | ClaimStep;
35	type Customer = { yearsWithMHPCO: number };
36	type Scenario = { customer: Customer; steps: Array<Step> };
37	type Policy = { items: Array<Item>; remainingCap: number };
38	
39	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
40	
41	const countBy = <T>(items: T[], keyOf: (item: T) => string): Record<string, number> => {
42	  const counts: Record<string, number> = {};
43	  for (const item of items) {
44	    const key = keyOf(item);
45	    counts[key] = (counts[key] ?? 0) + 1;
46	  }
47	  return counts;
48	};
49	
50	const typeOf = (item: Item): string => item.type;
51	const damageTypeOf = (damage: Damage): string => damage.itemType;
52	
53	const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
54	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
55	
56	const subtotalForType = (type: string, count: number): number =>
57	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
58	
59	const policyBaseFor = (items: Item[]): number =>
60	  sum(Object.entries(countBy(items, typeOf)).map(([type, count]) => subtotalForType(type, count)));
61	
62	const hasEnchantmentAtLeast = (item: Item, threshold: number): boolean =>
63	  (item.enchantment ?? 0) >= threshold;
64	
65	const isHighlyEnchanted = (item: Item): boolean =>
66	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
67	
68	const surchargeRate = (item: Item): number =>
69	  (item.cursed ? CURSED_SURCHARGE_RATE : 0) +
70	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
71	
72	const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);
73	
74	const itemSurchargesFor = (items: Item[]): number => sum(items.map(itemSurcharge));
75	
76	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
77	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
78	
79	const loyaltyDiscountFor = (policyBase: number, customer: Customer): number =>
80	  qualifiesForLoyaltyDiscount(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
81	
82	const firstInsuranceSurchargeFor = (policyBase: number): number =>
83	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
84	
85	const followUpDiscountFor = (policyBase: number, quoteIndex: number): number =>
86	  quoteIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
87	
88	const quotePremium = ({ items }: QuoteStep, customer: Customer, quoteIndex: number): number => {
89	  const policyBase = policyBaseFor(items);
90	  const surcharges = itemSurchargesFor(items) + firstInsuranceSurchargeFor(policyBase);
91	  const discounts = loyaltyDiscountFor(policyBase, customer) + followUpDiscountFor(policyBase, quoteIndex);
92	  return Math.ceil(policyBase + surcharges - discounts + PROCESSING_FEE);
93	};
94	
95	const insuranceSumFor = (items: Item[]): number =>
96	  sum(items.map((item) => insuranceValueFor(item.type)));
97	
98	const payoutRateFor = (item: Item): number =>
99	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) ? HIGH_ENCHANTMENT_PAYOUT_RATE : 1;
100	
101	const insuredItemOfType = (policy: Policy, itemType: string): Item =>
102	  policy.items.find((i) => i.type === itemType)!;
103	
104	const payoutForDamage = (damage: Damage, policy: Policy): number =>
105	  Math.floor(damage.amount * payoutRateFor(insuredItemOfType(policy, damage.itemType)) - DEDUCTIBLE);
106	
107	const validateNonNegativeAmounts = (damages: Damage[]): void => {
108	  const negative = damages.find((d) => d.amount < 0);
109	  if (negative) throw new Error(`Damage amount must be non-negative`);
110	};
111	
112	const validateDamageCounts = (damages: Damage[], policy: Policy): void => {
113	  const damageCounts = countBy(damages, damageTypeOf);
114	  const insuredCounts = countBy(policy.items, typeOf);
115	  for (const [type, count] of Object.entries(damageCounts)) {
116	    if (count > (insuredCounts[type] ?? 0)) {
117	      throw new Error(`Damage count for '${type}' exceeds insured count`);
118	    }
119	  }
120	};
121	
122	const validateDamages = (damages: Damage[], policy: Policy): void => {
123	  validateNonNegativeAmounts(damages);
124	  validateDamageCounts(damages, policy);
125	};
126	
127	const desiredPayoutFor = (damages: Damage[], policy: Policy): number =>
128	  sum(damages.map((d) => payoutForDamage(d, policy)));
129	
130	const processClaim = (step: ClaimStep, policies: Policy[]): { payout: number; remainingCap: number } => {
131	  const policy = policies[step.policy];
132	  validateDamages(step.incident.damages, policy);
133	  const payout = Math.min(desiredPayoutFor(step.incident.damages, policy), policy.remainingCap);
134	  policy.remainingCap -= payout;
135	  return { payout, remainingCap: policy.remainingCap };
136	};
137	
138	const capFor = (items: Item[]): number => insuranceSumFor(items) * CAP_MULTIPLIER;
139	
140	const newPolicy = (items: Item[]): Policy =>
141	  ({ items, remainingCap: capFor(items) });
142	
143	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
144	
145	const validateItemTypes = (items: Item[]): void => {
146	  const unknown = items.find((item) => !isKnownItemType(item.type));
147	  if (unknown) throw new Error(`Unknown item type: '${unknown.type}'`);
148	};
149	
150	const processQuote = (step: QuoteStep, customer: Customer, policies: Policy[]): { premium: number } => {
151	  validateItemTypes(step.items);
152	  const premium = quotePremium(step, customer, policies.length);
153	  policies.push(newPolicy(step.items));
154	  return { premium };
155	};
156	
157	export const runScenario = (input: unknown): unknown => {
158	  const scenario = input as Scenario;
159	  const policies: Policy[] = [];
160	  const results = scenario.steps.map((step) =>
161	    step.op === "quote"
162	      ? processQuote(step, scenario.customer, policies)
163	      : processClaim(step, policies)
164	  );
165	  return { results };
166	};
